import"./hoisted.CvN_TNCx.js";document.addEventListener("astro:page-load",()=>{const l=document.getElementById("quiz-form"),a=document.getElementById("result-modal");if(l instanceof HTMLFormElement&&a instanceof HTMLElement){const s=a.querySelector("#modal-score"),r=a.querySelector("#modal-text"),i=a.querySelector(".modal-close-btn");if(!(s instanceof HTMLParagraphElement)||!(r instanceof HTMLParagraphElement)||!(i instanceof HTMLButtonElement)){console.error("Quiz modal elements not found");return}l.addEventListener("submit",d=>{d.preventDefault();const u=new FormData(l);let e=0,m=!0;for(let t=1;t<=10;t++){if(!u.has("q"+t)){m=!1;break}const o=u.get("q"+t);o==="a"?e+=10:o==="b"?e+=7:o==="c"?e+=3:o==="d"&&(e+=0)}if(!m){alert("Harap jawab semua pertanyaan sebelum melihat hasil.");return}let n="";e>80?n="Wow, hubunganmu dengan ayah sangat dekat dan hangat! Kamu benar-benar mengenalnya dengan baik. Pertahankan terus, ya!":e>50?n="Hubunganmu dengan ayah cukup baik. Kamu sudah saling mengenal, tapi masih ada ruang untuk lebih dekat. Coba tingkatkan kualitas komunikasimu, ya!":n="Sepertinya ada sedikit jarak antara kamu dan ayah. Ini adalah kesempatan bagus untuk mulai membangun jembatan. Coba deh, luangkan waktu untuk ngobrol lebih sering, sekecil apapun itu.",s.textContent=`Skor kamu: ${e} dari 100`,r.textContent=n,a.classList.add("is-visible")}),i.addEventListener("click",()=>{a.classList.remove("is-visible")})}else console.error("Quiz form or modal not found")});
